import React, { useState, useEffect } from 'react';
import api from '../services/authService';
import { useFormValidation, ValidatedInput, ValidatedSelect, commonValidations } from './FormValidation';
import { useNotifications, useErrorHandler } from './NotificationSystem';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  sexo: string;
  categoria: string;
  estado: string;
  raza_nombre: string;
  ubicacion_nombre: string;
  fecha_nacimiento: string;
}

interface AnimalDetail extends Animal {
  peso_nacimiento: number;
  madre_id: number;
  padre_id: number;
  raza_id: number;
  ubicacion_actual_id: number;
  observaciones: string;
}

const Animals: React.FC = () => {
  const [animals, setAnimals] = useState<Animal[]>([]);
  const [razas, setRazas] = useState<any[]>([]);
  const [ubicaciones, setUbicaciones] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [showDetail, setShowDetail] = useState<number | null>(null);
  const [animalDetail, setAnimalDetail] = useState<AnimalDetail | null>(null);
  const { showSuccess, showError } = useNotifications();
  const { handleError } = useErrorHandler();

  const initialFormData = {
    identificador_unico: '',
    nombre: '',
    sexo: 'hembra',
    categoria: 'lechon',
    raza_id: '',
    fecha_nacimiento: '',
    peso_nacimiento: '',
    madre_id: '',
    padre_id: '',
    ubicacion_actual_id: '',
    observaciones: ''
  };

  const {
    values: formData,
    errors,
    touched,
    handleChange,
    handleBlur,
    validateForm,
    reset: resetValidation,
    setValues
  } = useFormValidation(initialFormData, {
    identificador_unico: {
      required: true,
      minLength: 3,
      maxLength: 20,
      pattern: /^[A-Za-z0-9-_]+$/,
      custom: (value) => {
        if (!value) return null;
        const exists = animals.some(a => 
          a.identificador_unico.toLowerCase() === value.toLowerCase() && 
          a.id !== editingId
        );
        return exists ? 'Este identificador ya existe' : null;
      }
    },
    nombre: { maxLength: 50 },
    sexo: { required: true },
    categoria: { required: true },
    peso_nacimiento: {
      min: 0.1,
      max: 10,
      custom: (value) => {
        if (!value) return null;
        const peso = parseFloat(value);
        if (isNaN(peso)) return 'Debe ser un número válido';
        return null;
      }
    },
    fecha_nacimiento: {
      custom: (value) => {
        if (!value) return null;
        const fecha = new Date(value);
        const hoy = new Date();
        if (fecha > hoy) return 'La fecha no puede ser futura';
        const hace2Anos = new Date();
        hace2Anos.setFullYear(hace2Anos.getFullYear() - 2);
        if (fecha < hace2Anos) return 'Fecha muy antigua (máximo 2 años)';
        return null;
      }
    }
  });

  useEffect(() => {
    loadAnimals();
    loadRazas();
    loadUbicaciones();
  }, []);

  const loadAnimals = async () => {
    try {
      const response = await api.get('/animals');
      setAnimals(response.data);
    } catch (error) {
      handleError(error, 'Error cargando animales');
    } finally {
      setLoading(false);
    }
  };

  const loadRazas = async () => {
    try {
      const response = await api.get('/animals/razas');
      setRazas(response.data);
    } catch (error) {
      handleError(error, 'Error cargando razas');
    }
  };

  const loadUbicaciones = async () => {
    try {
      const response = await api.get('/locations');
      setUbicaciones(response.data.filter((u: any) => u.tipo === 'corral'));
    } catch (error) {
      console.error('Error cargando ubicaciones:', error);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      showError('Formulario inválido', 'Por favor corrige los errores antes de continuar');
      return;
    }

    try {
      if (editingId) {
        await api.put(`/animals/${editingId}`, formData);
        showSuccess('Animal actualizado', 'Los datos se han actualizado correctamente');
      } else {
        await api.post('/animals', formData);
        showSuccess('Animal registrado', 'El animal se ha registrado exitosamente');
      }
      resetForm();
      loadAnimals();
    } catch (error) {
      handleError(error, 'Error guardando animal');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    resetValidation();
  };

  const handleEdit = async (id: number) => {
    try {
      const response = await api.get(`/animals/${id}`);
      const animal = response.data;
      setValues({
        identificador_unico: animal.identificador_unico,
        nombre: animal.nombre || '',
        sexo: animal.sexo,
        categoria: animal.categoria,
        raza_id: animal.raza_id?.toString() || '',
        fecha_nacimiento: animal.fecha_nacimiento || '',
        peso_nacimiento: animal.peso_nacimiento?.toString() || '',
        madre_id: animal.madre_id?.toString() || '',
        padre_id: animal.padre_id?.toString() || '',
        ubicacion_actual_id: animal.ubicacion_actual_id?.toString() || '',
        observaciones: animal.observaciones || ''
      });
      setEditingId(id);
      setShowForm(true);
    } catch (error) {
      handleError(error, 'Error cargando animal');
    }
  };

  const handleView = async (id: number) => {
    try {
      const response = await api.get(`/animals/${id}`);
      setAnimalDetail(response.data);
      setShowDetail(id);
    } catch (error) {
      console.error('Error cargando detalles:', error);
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm('¿Estás seguro de eliminar este animal?')) {
      try {
        await api.delete(`/animals/${id}`);
        showSuccess('Animal eliminado', 'El animal se ha eliminado correctamente');
        loadAnimals();
      } catch (error) {
        handleError(error, 'Error eliminando animal');
      }
    }
  };

  if (loading) return (
    <div className="loading">
      <div className="loading-spinner"></div>
      <p>Cargando animales...</p>
    </div>
  );

  return (
    <div className="fade-in">
      <div className="card-header">
        <div>
          <h1 className="card-title">🐷 Gestión de Animales</h1>
          <p style={{ color: '#7f8c8d', margin: 0 }}>Control completo del inventario animal</p>
        </div>
        <button 
          className="btn btn-primary"
          onClick={() => {
            if (showForm) {
              resetForm();
            } else {
              setShowForm(true);
            }
          }}
        >
          {showForm ? '❌ Cancelar' : '➕ Nuevo Animal'}
        </button>
      </div>

      {showForm && (
        <div className="card mb-4 fade-in">
          <div className="card-header">
            <h3 className="card-title">
              {editingId ? '✏️ Editar Animal' : '➕ Registrar Nuevo Animal'}
            </h3>
          </div>
          <form onSubmit={handleSubmit}>
            <div className="grid grid-2">
              <ValidatedInput
                name="identificador_unico"
                label="Identificador Único"
                value={formData.identificador_unico}
                error={errors.identificador_unico}
                touched={touched.identificador_unico}
                onChange={handleChange}
                onBlur={handleBlur}
                placeholder="Ej: CER001"
              />

              <ValidatedInput
                name="nombre"
                label="Nombre"
                value={formData.nombre}
                error={errors.nombre}
                touched={touched.nombre}
                onChange={handleChange}
                onBlur={handleBlur}
                placeholder="Nombre del animal (opcional)"
              />

              <ValidatedSelect
                name="sexo"
                label="Sexo"
                value={formData.sexo}
                error={errors.sexo}
                touched={touched.sexo}
                onChange={handleChange}
                onBlur={handleBlur}
                options={[
                  { value: 'hembra', label: 'Hembra' },
                  { value: 'macho', label: 'Macho' }
                ]}
              />

              <ValidatedSelect
                name="categoria"
                label="Categoría"
                value={formData.categoria}
                error={errors.categoria}
                touched={touched.categoria}
                onChange={handleChange}
                onBlur={handleBlur}
                options={[
                  { value: 'lechon', label: 'Lechón' },
                  { value: 'recria', label: 'Recría' },
                  { value: 'desarrollo', label: 'Desarrollo' },
                  { value: 'engorde', label: 'Engorde' },
                  { value: 'reproductor', label: 'Reproductor' }
                ]}
              />

              <ValidatedInput
                name="fecha_nacimiento"
                label="Fecha de Nacimiento"
                type="date"
                value={formData.fecha_nacimiento}
                error={errors.fecha_nacimiento}
                touched={touched.fecha_nacimiento}
                onChange={handleChange}
                onBlur={handleBlur}
              />

              <ValidatedSelect
                name="raza_id"
                label="Raza"
                value={formData.raza_id}
                error={errors.raza_id}
                touched={touched.raza_id}
                onChange={handleChange}
                onBlur={handleBlur}
                options={razas.map(raza => ({ value: raza.id.toString(), label: raza.nombre }))}
                placeholder="Seleccionar raza"
              />

              <ValidatedInput
                name="peso_nacimiento"
                label="Peso Nacimiento (kg)"
                type="number"
                value={formData.peso_nacimiento}
                error={errors.peso_nacimiento}
                touched={touched.peso_nacimiento}
                onChange={handleChange}
                onBlur={handleBlur}
                placeholder="1.5"
              />

              <ValidatedSelect
                name="madre_id"
                label="Madre"
                value={formData.madre_id}
                onChange={handleChange}
                onBlur={handleBlur}
                options={animals.filter(a => a.sexo === 'hembra' && a.categoria === 'reproductor').map(animal => ({
                  value: animal.id.toString(),
                  label: `${animal.identificador_unico} - ${animal.nombre || 'Sin nombre'}`
                }))}
                placeholder="Sin madre registrada"
              />

              <ValidatedSelect
                name="padre_id"
                label="Padre"
                value={formData.padre_id}
                onChange={handleChange}
                onBlur={handleBlur}
                options={animals.filter(a => a.sexo === 'macho' && a.categoria === 'reproductor').map(animal => ({
                  value: animal.id.toString(),
                  label: `${animal.identificador_unico} - ${animal.nombre || 'Sin nombre'}`
                }))}
                placeholder="Sin padre registrado"
              />

              <ValidatedSelect
                name="ubicacion_actual_id"
                label="Ubicación"
                value={formData.ubicacion_actual_id}
                onChange={handleChange}
                onBlur={handleBlur}
                options={ubicaciones.map(ubicacion => ({
                  value: ubicacion.id.toString(),
                  label: ubicacion.nombre
                }))}
                placeholder="Sin ubicación asignada"
              />

              <div className="form-group" style={{ gridColumn: '1 / -1' }}>
                <label htmlFor="observaciones">Observaciones:</label>
                <textarea
                  id="observaciones"
                  name="observaciones"
                  className="form-control"
                  rows={3}
                  value={formData.observaciones}
                  onChange={(e) => handleChange('observaciones', e.target.value)}
                  onBlur={() => handleBlur('observaciones')}
                  placeholder="Observaciones adicionales..."
                />
              </div>
            </div>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button type="submit" className="btn btn-success">
                {editingId ? '💾 Actualizar' : '💾 Guardar'} Animal
              </button>
              <button type="button" className="btn btn-secondary" onClick={resetForm}>
                ❌ Cancelar
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="card">
        <div className="card-header">
          <h3 className="card-title">📋 Lista de Animales ({animals.length})</h3>
          <div className="badge badge-info">{animals.length} registros</div>
        </div>
        {animals.length > 0 ? (
          <div className="table-container">
            <table className="table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Nombre</th>
                <th>Sexo</th>
                <th>Categoría</th>
                <th>Estado</th>
                <th>Raza</th>
                <th>Ubicación</th>
                <th>Nacimiento</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {animals.map(animal => (
                <tr key={animal.id}>
                  <td>{animal.identificador_unico}</td>
                  <td>{animal.nombre || '-'}</td>
                  <td>
                    <span className="badge" style={{
                      backgroundColor: animal.sexo === 'hembra' ? '#e91e63' : '#2196f3',
                      color: 'white'
                    }}>
                      {animal.sexo === 'hembra' ? '♀ Hembra' : '♂ Macho'}
                    </span>
                  </td>
                  <td>
                    <span className="badge badge-info" style={{ textTransform: 'capitalize' }}>
                      {animal.categoria}
                    </span>
                  </td>
                  <td>
                    <span className={`badge ${
                      animal.estado === 'activo' ? 'badge-success' : 
                      animal.estado === 'vendido' ? 'badge-warning' : 'badge-danger'
                    }`}>
                      {animal.estado === 'activo' ? '✅ Activo' : 
                       animal.estado === 'vendido' ? '💰 Vendido' : '❌ ' + animal.estado}
                    </span>
                  </td>
                  <td>{animal.raza_nombre || '-'}</td>
                  <td>{animal.ubicacion_nombre || '-'}</td>
                  <td>{animal.fecha_nacimiento ? new Date(animal.fecha_nacimiento).toLocaleDateString() : '-'}</td>
                  <td>
                    <div className="action-buttons">
                      <button 
                        className="btn btn-info btn-sm"
                        onClick={() => handleView(animal.id)}
                        title="Ver detalles"
                      >
                        👁️
                      </button>
                      <button 
                        className="btn btn-warning btn-sm"
                        onClick={() => handleEdit(animal.id)}
                        title="Editar"
                      >
                        ✏️
                      </button>
                      <button 
                        className="btn btn-danger btn-sm"
                        onClick={() => handleDelete(animal.id)}
                        title="Eliminar"
                      >
                        🗑️
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
            </table>
          </div>
        ) : (
          <div className="empty-state">
            <div className="empty-state-icon">🐷</div>
            <h3>No hay animales registrados</h3>
            <p>Comienza registrando tu primer animal en el sistema</p>
            <button className="btn btn-primary" onClick={() => setShowForm(true)}>
              ➕ Registrar Primer Animal
            </button>
          </div>
        )}
      </div>

      {/* Modal de detalles */}
      {showDetail && animalDetail && (
        <div className="modal-overlay">
          <div className="card modal-content">
            <div className="card-header">
              <h3 className="card-title">🐷 Detalles del Animal</h3>
              <button 
                className="btn btn-secondary btn-sm"
                onClick={() => setShowDetail(null)}
              >
                ❌
              </button>
            </div>
            <div className="grid grid-2">
              <div>
                <strong>ID:</strong> {animalDetail.identificador_unico}
              </div>
              <div>
                <strong>Nombre:</strong> {animalDetail.nombre || 'Sin nombre'}
              </div>
              <div>
                <strong>Sexo:</strong> {animalDetail.sexo}
              </div>
              <div>
                <strong>Categoría:</strong> {animalDetail.categoria}
              </div>
              <div>
                <strong>Estado:</strong> {animalDetail.estado}
              </div>
              <div>
                <strong>Raza:</strong> {animalDetail.raza_nombre || 'No especificada'}
              </div>
              <div>
                <strong>Fecha Nacimiento:</strong> {animalDetail.fecha_nacimiento ? new Date(animalDetail.fecha_nacimiento).toLocaleDateString() : 'No especificada'}
              </div>
              <div>
                <strong>Peso Nacimiento:</strong> {animalDetail.peso_nacimiento ? `${animalDetail.peso_nacimiento} kg` : 'No registrado'}
              </div>
              <div>
                <strong>Ubicación:</strong> {animalDetail.ubicacion_nombre || 'No asignada'}
              </div>
            </div>
            {animalDetail.observaciones && (
              <div style={{ marginTop: '15px' }}>
                <strong>Observaciones:</strong>
                <p style={{ marginTop: '5px', padding: '10px', backgroundColor: '#f8f9fa', borderRadius: '4px' }}>
                  {animalDetail.observaciones}
                </p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Animals;
